typedef struct {
    long long dist;
    int u;
} Node;

// Min-Heap Push
void pushNode(Node** heap_ptr, int* size, Node val) {
    Node* heap = *heap_ptr;
    int i = (*size)++;
    heap[i] = val;
    while (i != 0 && heap[(i - 1) / 2].dist > heap[i].dist) {
        Node temp = heap[i];
        heap[i] = heap[(i - 1) / 2];
        heap[(i - 1) / 2] = temp;
        i = (i - 1) / 2;
    }
}

// Min-Heap Pop
Node popNode(Node* heap, int* size) {
    Node root = heap[0];
    heap[0] = heap[--(*size)];
    int i = 0;
    while (1) {
        int left = 2 * i + 1;
        int right = 2 * i + 2;
        int smallest = i;

        if (left < *size && heap[left].dist < heap[smallest].dist)
            smallest = left;
        if (right < *size && heap[right].dist < heap[smallest].dist)
            smallest = right;

        if (smallest != i) {
            Node temp = heap[i];
            heap[i] = heap[smallest];
            heap[smallest] = temp;
            i = smallest;
        } else {
            break;
        }
    }
    return root;
}
int countShortestPaths(int totalIntersections, int roadsList[][3], int numRoads) {
    int n = totalIntersections;
    if (n <= 1) return 1;

    // 1. Build Adjacency List for Undirected Graph
    // Max nodes = 200, Max Edges = 20000 * 2 (undirected) = 40000
    int head[205];
    int to[40005];
    int weight[40005];
    int next_edge[40005];
    int edge_cnt = 0;

    for (int i = 0; i <= n; i++) {
        head[i] = -1;
    }

    for (int i = 0; i < numRoads; i++) {
        int u = roadsList[i][0];
        int v = roadsList[i][1];
        int w = roadsList[i][2];

        to[edge_cnt] = v;
        weight[edge_cnt] = w;
        next_edge[edge_cnt] = head[u];
        head[u] = edge_cnt++;

        to[edge_cnt] = u;
        weight[edge_cnt] = w;
        next_edge[edge_cnt] = head[v];
        head[v] = edge_cnt++;
    }

    // 2. Initialize Distances and Ways Arrays
    long long dist[205];
    long long ways[205];
    for (int i = 0; i <= n; i++) {
        dist[i] = INF;
        ways[i] = 0;
    }

    dist[0] = 0;
    ways[0] = 1;

    // 3. Setup Min-Heap Priority Queue
    Node* pq = (Node*)malloc(100005 * sizeof(Node));
    int pq_size = 0;

    pushNode(&pq, &pq_size, (Node){0, 0});

    // 4. Run Dijkstra Algorithm
    while (pq_size > 0) {
        Node cur = popNode(pq, &pq_size);
        long long d = cur.dist;
        int u = cur.u;

        // Skip stale states in the priority queue
        if (d > dist[u]) continue;

        for (int e = head[u]; e != -1; e = next_edge[e]) {
            int v = to[e];
            long long w = weight[e];

            // Condition 1: Found a strictly shorter path
            if (d + w < dist[v]) {
                dist[v] = d + w;
                ways[v] = ways[u];
                pushNode(&pq, &pq_size, (Node){dist[v], v});
            } 
            // Condition 2: Found an equally short alternate path
            else if (d + w == dist[v]) {
                ways[v] = (ways[v] + ways[u]) % MOD;
            }
        }
    }

    int ans = ways[n - 1] % MOD;
    free(pq);

    return ans;
}

