const MOD = 1000000007;

class Solution {
    countShortestPaths(totalIntersections, roadsList) {
        const n = totalIntersections;

        // Build adjacency list
        const adj = Array.from({ length: n }, () => []);
        for (const [u, v, time] of roadsList) {
            adj[u].push([v, time]);
            adj[v].push([u, time]);
        }

        // Dijkstra
        const dist = Array(n).fill(Infinity);
        const ways = Array(n).fill(0);

        dist[0] = 0;
        ways[0] = 1;

        // Min-heap: [distance, node]
        const pq = [];
        pq.push([0, 0]);

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]); // simple heap replacement
            const [currDist, node] = pq.shift();

            if (currDist > dist[node]) continue;

            for (const [next, weight] of adj[node]) {
                const newDist = currDist + weight;

                if (newDist < dist[next]) {
                    dist[next] = newDist;
                    ways[next] = ways[node];
                    pq.push([newDist, next]);
                } else if (newDist === dist[next]) {
                    ways[next] = (ways[next] + ways[node]) % MOD;
                }
            }
        }

        return ways[n - 1];
    }
}
